10130 bool BoUpSLP::isFullyVectorizableTinyTree(bool ForReduction) const {
10131   LLVM_DEBUG(dbgs() << "SLP: Check whether the tree with height "
10132                     << VectorizableTree.size() << " is fully vectorizable .\n");
